var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"於是你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"아, 그래. 언제 이 얘길 하나 했지.","JPN":"あ、そうか。いつこの話を持ちだすのかと思ってた。","ENG":"Ah, yes. I was wondering when you were going to ask.","TWN":"啊，是啊，正好等著你說這句。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"완전체인 내 힘을 알게 된 이상 붙잡아 두고 싶어지는 게 당연하거든.","JPN":"完全体であるアタシの力を知った以上、引き止めたくなるのも当然だな。","ENG":"Now that you know my power as a united type, there's no way you'll want to let me go.","TWN":"既然知道了完整體的我的力量，當然就想留住我是理所當然的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그런데 말이야.","JPN":"だけどな。","ENG":"But...","TWN":"可是啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"내가 저런 월급쟁이 나부랭이들이랑 똑같은 취급을 받아야겠냐?","JPN":"アタシをあんなサラリーマン連中なんかと一緒にしないでくれるか？","ENG":"Why would I want to be treated like an employee?","TWN":"我必需受到和那些上班族一樣的對待嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"네가 사장인지 뭔지, 회사니 어쩌니 난 쥐뿔도 관심 없어.","JPN":"アタシはお前が社長だか何だか知らないし、会社とかにちっとも興味がない。","ENG":"I don't care if you're the CEO of this company.","TWN":"至於你是不是這家公司的老闆，我其實也不太在意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"너란 녀석이 마음에 드니까 좀 어울려 줬을 뿐이지.","JPN":"お前という奴が気に入ったから、\\nちょっとだけ付き合ってあげただけだ。","ENG":"I've stayed around so far because I like you as a person.","TWN":"因為我喜歡你才跟你相處了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"불량품들 데리고 다니는 것도 이제 질렸거든. 역시 쥐새끼들처럼 뭉쳐 다니는 건 내 성미에 안 맞아.","JPN":"出来損ないどもを連れ歩くのも、もううんざりなんだ。やっぱりネズミみたいに群れて行動するのは性に合わない。","ENG":"I'm tired of being held back by defectives. Moving in groups like a pack of rats isn't my thing, either.","TWN":"已經厭倦了帶不良品出門了。果然像老鼠一樣聚在一起不符合我的個性。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"차라리 말귀 잘 알아듣는 녀석 하나 골라다 옆에 데리고 다니는 편이 더 낫겠지.","JPN":"いっそ聞き分けのいい奴を一人選んで連れ歩くほうが楽だな。","ENG":"I'd rather be with a single sidekick who understands me.","TWN":"還不如挑一個能聽懂話的傢伙帶在身邊更好。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"축하해. 그 녀석이 바로 너야.","JPN":"おめでとう。それがまさにお前だ。","ENG":"And congrats, that's you.","TWN":"恭喜啊，那傢伙就是你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭐, 그렇다고 너무 겁먹지는 말라고.","JPN":"まぁ、だからといってそんなにビビるなよ。","ENG":"Well, there's no need to be scared.","TWN":"呃，也不用那麼害怕了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"쥐새끼들이 거슬리게만 하지 않으면 당분간은 조용히 지낼 테니까.","JPN":"ネズミどもが邪魔さえしなければ、当分は大人しくするからさ。","ENG":"I'll keep a low profile so long as the rats don't bother me.","TWN":"如果老鼠們不礙眼的話，暫時可以安靜的生活了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};